INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('elementary-e0adf6cd-moex-00659', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-111-01c5eaab', 'sub-elementary-e0adf6cd-05', NULL, 'single_choice', '「資訊時代的到來，網路徹底改變了人類的生活方式。各行各業經網路系統重新佈局，與世界各國 接軌，網路是個新世界，這個世界的人被稱作網民，這個網愈結愈實，愈張愈大，網民以幾何級數 增長。走進電腦網路，可以遨遊世界，談生意，開會討論。教育工作者一樣感受到電腦的便捷，過 去演講，要請專人製幻燈片，不但要等時間，做好也無法修改。如今自己動手用 Powerpoint 做投影 片，方便迅速，還可隨意更換背景以美化畫面。此外，網路資訊豐富，就像一本百科全書，隨時提 供查閱。」 依據上文，全文的主旨為何？', '["網路發展拉近了人類的距離", "網路發展減少人類溝通問題", "網路改變人類的生活和文化", "電子郵件使人們聯繫更便捷"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:41+00:00", "source_pdf_sha1": "6590d4ee65e2", "answer_pdf_sha1": "e24c36da3da8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "504", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00660', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-111-01c5eaab', 'sub-elementary-e0adf6cd-05', NULL, 'single_choice', '「我們這兩代，共同照顧農村的新生代，然而，孩子們變成什麼樣子？他們背著很重的書包，在學 校、補習班和家裡三處來回移動；他們鮮少靠近土地、觸摸作物，有空就盯著平板不放、開著電視 節目配晚餐；他們暫時留在鄉下，一上小學或上了國中，就會被帶到都市加入更激烈的求學競爭； 他們踩在田裡就踮腳、沾到泥土就猛拍、看到螞蟻就大叫，也總認為自來水比圳水清澈乾淨。孩子 們生在農村，卻不是在農村活著，他們隨著大人的安排，想盡辦法要離開農村。」 依據上文，作者筆下「農村新生代」離開農村的原因何在？', '["即使是農村，也難逃升學壓力，補習班的影響力深遠", "新生代從小嬌生慣養，家事均由大人代勞，缺乏自我謀生的能力", "在功利主義的社會文化之下，孩子以升學為目標，被抽離土地，缺乏認同", "在電子媒體的時代，如果留在農村，就容易與外界隔絕，沒有辦法跟得上"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:41+00:00", "source_pdf_sha1": "6590d4ee65e2", "answer_pdf_sha1": "e24c36da3da8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "504", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00661', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-111-01c5eaab', 'sub-elementary-e0adf6cd-05', NULL, 'single_choice', '「這是一個最尖銳的問題。莫里老人自己回答道：『我當然在受罪。但給予他人，能使我感到自己 還活著。汽車和房子不能給你這種感覺，鏡子裡照出的模樣也不能給你這種感覺。只有當我奉獻出 了時間，當我使那些悲傷的人又露出笑顏，我才感到我仍像以前一樣健康。』這樣，他就道出了生 命的根本意義。」 文中作者所謂的「生命根本意義」是：', '["善用所有時間", "生活無憂無慮", "長保青春歡顏", "樂於幫助他人"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:41+00:00", "source_pdf_sha1": "6590d4ee65e2", "answer_pdf_sha1": "e24c36da3da8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "504", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00662', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-111-01c5eaab', 'sub-elementary-e0adf6cd-05', NULL, 'single_choice', '「法國前總理有一次視察某地，手中拎著個超級市場的塑膠袋，接受採訪時，這個袋子也一直拎在 手上，看起來非常自然，並沒有誰覺得他寒酸，沒有誰覺得他不夠紳士，人們反而對他投以欽佩的 目光。」 下列選項，何者最接近法國前總理的表現？', '["節能生活，由自我做起", "為譁眾取寵而特立獨行", "人人平等，並無貴賤之分", "有自信的人不受外界眼光影響"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:41+00:00", "source_pdf_sha1": "6590d4ee65e2", "answer_pdf_sha1": "e24c36da3da8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "504", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00663', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-111-01c5eaab', 'sub-elementary-e0adf6cd-05', NULL, 'single_choice', '「波特萊爾的詩：『老巴黎消失了／一座城市的形體，唉，有著比人心還要更快的變化。』所謂比 人心更快的變化，特別指向有限的、必定會消亡的生命。人必有死，相較於以磚石所造的城市，人 壽如此有限，而人的感受與念頭，又是人類經驗中變動最快的。波特萊爾走過巴黎街道時，如同被 電擊般意識到，他所居住的城市已經徹底失去其恆常特性，以讓人無從準備防備的速度，持續變化。 應該提供我們安穩依賴的磚石之物，背叛了我們的期待，翻身比我們念頭的轉換，變得更快更劇烈。」 下列選項，何者不是這段文章所要傳達的意旨？', '["建造城市所需的磚石之物，有恆常特性，永遠不會消失", "有限的、必定會消亡的生命，不只是人，還包括老巴黎", "我們以為人心變化很快，實際上城市的變化可能比人心還快", "作者最終要傳達的是，人心變動太快，把磚石穩固的城市也改變"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:41+00:00", "source_pdf_sha1": "6590d4ee65e2", "answer_pdf_sha1": "e24c36da3da8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "504", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00664', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-111-01c5eaab', 'sub-elementary-e0adf6cd-05', NULL, 'single_choice', '「凡不肯說謝謝的人，是一個驕傲冷橫的人，他覺得在這世界過的是『銀貨兩訖』的日子。他是工 商業社會的產物，他覺得他不欠誰，不求誰，他所擁有的東西都是他該得的，所以他不需要向誰說 『謝謝』。但我知道，我並不『該』得什麼，我曾赤手空拳來到這個世界，沒有人『該』愛我，沒 有人『該』養我，沒有人『該』為我廢寢忘食，出入攜抱。我也許繳了學費，但老師那份關懷器重 是我買得到的嗎？我也許付了米錢，但農夫的辛勞豈是我那一點錢報償得了的？」 「我曾赤手空拳來到這個世界」，「赤手空拳」的「赤」非指顏色，而有「空無一物」的意思。下 列選項，非指顏色的是：', '["「白」手起家", "「黃」梅時節", "「黑」布馬褂", "「綠」煙紅霧"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:41+00:00", "source_pdf_sha1": "6590d4ee65e2", "answer_pdf_sha1": "e24c36da3da8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "504", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00665', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-111-01c5eaab', 'sub-elementary-e0adf6cd-05', NULL, 'single_choice', '承上題，本文意旨為：', '["凡事應心存感恩", "人不可錙銖必較", "禮貌使社會溫暖", "金錢絕不是萬能"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:41+00:00", "source_pdf_sha1": "6590d4ee65e2", "answer_pdf_sha1": "e24c36da3da8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "504", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00666', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-111-01c5eaab', 'sub-elementary-e0adf6cd-05', NULL, 'single_choice', '「理想的下午，當消使在理想的地方，通常這地方是在城市。幽靜田村，風景美極，空氣水質好極， 卻是清晨夜晚都好，下午難免苦長。理想的下午，有賴理想的下午人。這類人樂意享受外間。樂意 暫且擱下手邊工作，樂意走出舒適的廳房、關掉柔美的音樂、闔上津津有味的書籍，套上鞋往外而 去。也只是漫無目的的走，看看市景，聽聽人聲。穿過馬路，登上台階，時而進入公園，看一眼花 草，瞧一眼池魚。揀一方大石或鐵椅坐下，不時側聽鄰客高談時政，嗅著飄來的香菸味，置之一笑。 有時翻閱小報，悄然睏去。醒來只覺眼前景物的色調略呈灰藍，像套了濾色鏡，不似先前那麼光燦 了，竟如同眾人散場多時只遺自己一個的那股辰光向晚寂寂。然一看錶，只過了十五分鐘。」 根據上文，下列何者最符合作者所謂「理想的下午」？', '["請假半天，在幽靜的山間園林尋幽訪勝", "暫時放下工作，帶一本小書到公園長椅上閒坐閱讀", "坐在城市的小咖啡廳，欣賞音樂與窗外風景，嗅著鄰座飄來的菸味", "帶著一顆悠閒的心，在城市中漫步閒坐，隨意地體驗城市中的百態"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:41+00:00", "source_pdf_sha1": "6590d4ee65e2", "answer_pdf_sha1": "e24c36da3da8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "504", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00667', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-111-01c5eaab', 'sub-elementary-e0adf6cd-05', NULL, 'single_choice', '承上題，作者認為「理想的下午」應該發生在城市中，依引文推測，最可能的原因是什麼？', '["身處在熱鬧塵俗之中，正可以靜觀世間多種趣味", "偷得浮生半日閒，時間所限，難以探訪鄉間美景", "交通方便，商業活動頻繁，可以調劑無聊的午後", "城市中人來人往，個人做什麼都不至於感到孤寂"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:41+00:00", "source_pdf_sha1": "6590d4ee65e2", "answer_pdf_sha1": "e24c36da3da8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "504", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00668', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-111-01c5eaab', 'sub-elementary-e0adf6cd-05', NULL, 'single_choice', '「財團法人國家文化藝術基金會」為辦理「國家文藝獎」，請全國文教機構與相關單位，推薦適當 人選，其使用之公文為：', '["簽", "呈", "咨", "函"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:41+00:00", "source_pdf_sha1": "6590d4ee65e2", "answer_pdf_sha1": "e24c36da3da8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "504", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL)
